/**
 * Forkjoin Binary Lexicon
 *
 * Core definitions for the monorepo's universal binary grammar.
 * All payloads follow the Common Payload Header (8 bytes) for
 * alignment and integrity.
 *
 * This is the canonical home of the Lexicon. Dash re-exports it
 * from `@a0n/gnosis/lexicon` to avoid a circular dependency.
 */

export const LEXICON_VERSION = 1;
export const COMMON_HEADER_SIZE = 8;
export const COMMON_HEADER_LARGE_SIZE = 12;

export const FLAG_LARGE = 0x80; // Extended payload length (12-byte header)
export const FLAG_RLE = 0x40;   // Run-Length Encoding for crossings (Surface-Aware)
export const FLAG_HOMOGENEOUS_IDS = 0x20; // All crossings share the same node ID (deduplicated)

/**
 * Magic Byte Lexicon Registry
 */
export const MAGIC = {
  /** BitwiseDNA (2-bit sequences) */
  BITWISE: [0x42, 0x57], // BW
  /** Gnot (Global Network Optimized Tree / GG topology) */
  GNOT: [0x47, 0x4b], // GK
  /** Gnot alias (Deprecated: use GNOT) */
  KNOT: [0x47, 0x4b], // GK
  /** Alphabet Wire (Packed sequences) */
  ALPHABET: [0x41, 0x57], // AW
  /** LinK (Cross-stream pointer) */
  LINK: [0x4c, 0x4b], // LK
  /** TYpe (Schema / Reflection) */
  TYPE: [0x54, 0x59], // TY
  /** MetaData (Key-Value attributes) */
  METADATA: [0x4d, 0x44], // MD
  /** AUth (Signed identity / Claim) */
  AUTH: [0x41, 0x55], // AU
  /** EVent (Temporal trigger) */
  EVENT: [0x45, 0x56], // EV
  /** TRace (Observability ID) */
  TRACE: [0x54, 0x52], // TR
  /** QuantuM (State vector) */
  QUANTUM: [0x51, 0x4d], // QM
  /** HEartbeat (Liveness pulse) */
  HEARTBEAT: [0x48, 0x45], // HE
  /** QDoc (CRDT Envelope) */
  QDOC: [0x51, 0x44], // QD
  /** INterfere (Phase alignment) */
  INTERFERE: [0x49, 0x4e], // IN
  /** Routing Tokens (β₁-Adaptive Compute) */
  ROUTING: [0x52, 0x54], // RT
  /** BLOB (Large binary objects) */
  BLOB: [0x42, 0x4c], // BL
  // --- C Data Structures ---
  /** ARray (Contiguous elements) */
  ARRAY: [0x41, 0x52], // AR
  /** STruct (Compound record) */
  STRUCT: [0x53, 0x54], // ST
  /** LinkedList (Chained pointers) */
  LINKED_LIST: [0x4c, 0x4c], // LL
  /** UNion (Tagged variants) */
  UNION: [0x55, 0x4e], // UN
  /** ENum (Ordinal categories) */
  ENUM: [0x45, 0x4e], // EN
  /** MaP (Associated key-values) */
  MAP: [0x4d, 0x50], // MP
  /** SEt (Unique items) */
  SET: [0x53, 0x45], // SE
  // --- Gnosis Specifics ---
  /** SLice (Multidimensional window) */
  SLICE: [0x53, 0x4c], // SL
  /** VoiD (Topological boundary) */
  VOID: [0x56, 0x44], // VD
  /** TeNsor (Mathematical array) */
  TENSOR: [0x54, 0x4e], // TN
  /** EMergence (State shift) */
  EMERGENCE: [0x45, 0x4d], // EM
  // --- Block Index ---
  /** IndeX (Frame offset table for block scanning) */
  INDEX: [0x49, 0x58], // IX
  /** DNA (Biochemical Sequence / Gnot Genome) */
  DNA: [0x44, 0x4e], // DN
  /** GRSM (Grassmannian Amplituhedron Tensor) */
  GRSM: [0x47, 0x52], // GR
} as const;

export type MagicType = keyof typeof MAGIC;

/**
 * CRC-16-CCITT (False)
 * Polynomial: 0x1021, Initial: 0xFFFF
 */
export function crc16(data: Uint8Array): number {
  let crc = 0xffff;
  for (let i = 0; i < data.length; i++) {
    crc ^= (data[i] ?? 0) << 8;
    for (let j = 0; j < 8; j++) {
      if (crc & 0x8000) {
        crc = (crc << 1) ^ 0x1021;
      } else {
        crc <<= 1;
      }
      crc &= 0xffff;
    }
  }
  return crc & 0xffff;
}

/**
 * CRC-32C (Castagnoli)
 * Polynomial: 0x82F63B78
 */
export function crc32(data: Uint8Array): number {
  let crc = 0xffffffff;
  for (let i = 0; i < data.length; i++) {
    crc ^= data[i] ?? 0;
    for (let j = 0; j < 8; j++) {
      if (crc & 1) {
        crc = (crc >>> 1) ^ 0x82f63b78;
      } else {
        crc >>>= 1;
      }
    }
  }
  return (crc ^ 0xffffffff) >>> 0;
}

export interface CommonHeader {
  magic: number[];
  version: number;
  flags: number;
  crc: number;
  payloadLength: number;
}

/**
 * Write a common header to a Uint8Array.
 * The array must be at least 8 bytes.
 */
export function writeHeader(
  buffer: Uint8Array,
  magic: readonly [number, number],
  payloadLength: number,
  opts?: { version?: number; flags?: number; crc?: number }
): void {
  buffer[0] = magic[0];
  buffer[1] = magic[1];
  buffer[2] = opts?.version ?? LEXICON_VERSION;
  buffer[3] = opts?.flags ?? 0;
  
  // CRC and Length depend on FLAG_LARGE
  const isLarge = (buffer[3] & FLAG_LARGE) !== 0;
  const crc = opts?.crc ?? 0;

  if (isLarge) {
    const view = new DataView(buffer.buffer, buffer.byteOffset, buffer.byteLength);
    view.setUint32(4, crc, false); // 4-byte CRC
    view.setUint32(8, payloadLength, false); // 4-byte Length
  } else {
    buffer[4] = (crc >> 8) & 0xff;
    buffer[5] = crc & 0xff;
    buffer[6] = (payloadLength >> 8) & 0xff;
    buffer[7] = payloadLength & 0xff;
  }
}

/**
 * Read a common header from a Uint8Array.
 */
export function readHeader(buffer: Uint8Array): CommonHeader | null {
  if (buffer.length < COMMON_HEADER_SIZE) return null;
  
  const flags = buffer[3] ?? 0;
  const isLarge = (flags & FLAG_LARGE) !== 0;

  let crc: number;
  let payloadLength: number;

  if (isLarge) {
    const view = new DataView(buffer.buffer, buffer.byteOffset, buffer.byteLength);
    crc = view.getUint32(4, false);
    payloadLength = view.getUint32(8, false);
  } else {
    crc = ((buffer[4] ?? 0) << 8) | (buffer[5] ?? 0);
    payloadLength = ((buffer[6] ?? 0) << 8) | (buffer[7] ?? 0);
  }

  return {
    magic: [buffer[0] ?? 0, buffer[1] ?? 0],
    version: buffer[2] ?? 0,
    flags,
    crc,
    payloadLength,
  };
}

/**
 * Verify physical payload CRC.
 */
export function verifyPayload(
  header: CommonHeader,
  payload: Uint8Array
): boolean {
  // If CRC is 0, we assume it's uncomputed (optional check)
  if (header.crc === 0) return true;
  
  const isLarge = (header.flags & FLAG_LARGE) !== 0;
  if (isLarge) {
    return crc32(payload) === header.crc;
  }
  return (crc16(payload) & 0xffff) === header.crc;
}

/**
 * Write a variable-length integer (LEB128-style).
 * Returns the number of bytes written.
 */
export function writeVarint(buffer: Uint8Array, offset: number, val: number): number {
  let v = val;
  let pos = offset;
  while (v >= 0x80) {
    buffer[pos++] = (v & 0x7f) | 0x80;
    v >>>= 7;
  }
  buffer[pos++] = v & 0x7f;
  return pos - offset;
}

/**
 * Read a variable-length integer (LEB128-style).
 * Returns { value, bytesRead }.
 */
export function readVarint(buffer: Uint8Array, offset: number): { value: number; bytesRead: number } {
  let value = 0;
  let shift = 0;
  let pos = offset;
  while (true) {
    const byte = buffer[pos++] ?? 0;
    value |= (byte & 0x7f) << (shift >>> 0);
    if ((byte & 0x80) === 0) break;
    shift += 7;
    if (shift >= 32) break;
  }
  return { value, bytesRead: pos - offset };
}
